   209 |   // or a trunc of the 'and'.
   210 |   if (ValZeros > AndZeros) {
   211 |     V = Builder.CreateZExtOrTrunc(V, SelType);
   212 |     V = Builder.CreateShl(V, ValZeros - AndZeros);
   213 |   } else if (ValZeros < AndZeros) {
